Javascript.isEnabled:
var N39En = IsN39Reqd.isEnabled();
var isN39Req = Services.getValue(IsN39Reqd.dataBinding);
return( !N39En || 'Y' == isN39Req);

Javascript.logic:
var N39En = IsN39Reqd.isEnabled();
var isN39Req = Services.getValue(IsN39Reqd.dataBinding);

//event 450
if( N39En  )
{	
	if('Y' == isN39Req)
	{  Services.setValue(QuestionWho.dataBinding, "D");
	}
	else
	{	Services.setValue(QuestionWho.dataBinding, "");
	}

}
